float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5)*uAspect.xy;


vec3 noiseVal =lum (texture(sampler_noise_lq, corr*vUv*.02+ .1*rand_frame));

vec2 k1 = vec2((vUv.x), (vUv.y));

vec3 ret1 = GetBlur1(vUv) ;

float k2 = (40*vUv)%8;

vec2 zz = vUv.xy * uTexSize.xy *.3;
float h1 = (tan(zz.x));
float h2 = (tan(zz.y));

vUv.xy -= vec2(h1,h2)*uTexSize.zw * 3;


